// extractTitle extracts the content of the <title> tag.
func extractTitle(html []byte) string {
	// Simple regex to find <title>...</title>
	re := regexp.MustCompile(`(?i)<title[^>]*>(.*?)</title>`)
	matches := re.FindSubmatch(html)
	if len(matches) > 1 {
		return string(bytes.TrimSpace(matches[1]))
	}
	return ""
}

// extractMetaDescription extracts the content of the meta description tag.
func extractMetaDescription(html []byte) string {
	// Regex to find <meta name="description" content="...">
	re := regexp.MustCompile(`(?i)<meta\s+name=["']description["']\s+content=["']([^"']*)["']`)
	matches := re.FindSubmatch(html)
	if len(matches) > 1 {
		return string(bytes.TrimSpace(matches[1]))
	}

	// Regex to find <meta content="..." name="description">
	re = regexp.MustCompile(`(?i)<meta\s+content=["']([^"']*)["']\s+name=["']description["']`)
	matches = re.FindSubmatch(html)
	if len(matches) > 1 {
		return string(bytes.TrimSpace(matches[1]))
	}

	return ""
}

func main() {
	// Setup the handler
	// Note: In a real application, you might want to wrap this with CORS middleware, etc.
	fasthttp.ListenAndServe(":8080", func(ctx *fasthttp.RequestCtx) {
		// Simple routing: only handle POST to /preview
		if string(ctx.Path()) == "/preview" && ctx.IsPost() {
