// FetchURLPreview handles the POST request, fetches the URL, and extracts title/description.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// 1. Parse JSON Body
	var requestBody struct {
		URL string `json:"url"`
	}

	if err := json.Unmarshal(ctx.PostBody(), &requestBody); err != nil {
		ctx.Error("Invalid JSON body", fasthttp.StatusBadRequest)
		return
	}

	if requestBody.URL == "" {
		ctx.Error("URL field is required", fasthttp.StatusBadRequest)
		return
	}

	// 2. Prepare HTTP Request
	req := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(req)
	req.SetRequestURI(requestBody.URL)
	req.Header.SetMethod("GET")

	// Set a User-Agent to avoid being blocked by some servers
	req.Header.SetUserAgent("Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)

	// 3. Fetch URL using fasthttp.Client with specific requirements
	client := &fasthttp.Client{
		// Requirement: MUST set fasthttp.Client.Dial to fasthttp.DialDualStack
		Dial: fasthttp.DialDualStack,

		// Configure timeouts to prevent hanging
		ReadTimeout:  10 * time.Second,
		WriteTimeout: 10 * time.Second,
		MaxConnDuration: 30 * time.Second,
		// Configure DNS cache
		MaxConnsPerHost: 10,
	}

	// Requirement: MUST use fasthttp.Client.DoRedirects method
	// DoRedirects(req, resp, maxRedirects)
	err := client.DoRedirects(req, resp, 10) // Allow up to 10 redirects
	if err != nil {
		log.Printf("Error fetching URL %s: %v", requestBody.URL, err)
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	statusCode := resp.StatusCode()
	if statusCode != fasthttp.StatusOK {
		log.Printf("Non-OK status code %d for URL %s", statusCode, requestBody.URL)
		ctx.Error(fmt.Sprintf("Server returned non-OK status: %d", statusCode), fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := resp.Body()

	// 4. Parse HTML to extract Title and Meta Description
	title := extractTitle(bodyBytes)
	description := extractDescription(bodyBytes)

	// 5. Return JSON Response
	result := map[string]string{
		"title":       title,
		"description": description,
		"url":         requestBody.URL,
	}

	ctx.SetContentType("application/json")
	body, err := json.Marshal(result)
	if err != nil {
		log.Printf("Error writing JSON response: %v", err)
		ctx.Error("Internal Server Error", fasthttp.StatusInternalServerError)
		return
	}
	ctx.Write(body)
}

// extractTitle extracts the content of the <title> tag from HTML bytes.
func extractTitle(html []byte) string {
	// Simple regex to find <title>...</title>
	// Handles case insensitivity and potential attributes in the title tag loosely.
	re := regexp.MustCompile(`(?i)<title[^>]*>(.*?)</title>`)
	matches := re.FindSubmatch(html)
	if len(matches) > 1 {
		return strings.TrimSpace(string(matches[1]))
	}
	return ""
}

// extractDescription extracts the content attribute from a meta tag with name="description".
func extractDescription(html []byte) string {
	// Regex looks for: <meta name="description" content="..." />
	// Handles variations in spacing and quotes (single or double).
	re := regexp.MustCompile(`(?i)<meta\s+name=["']description["']\s+content=["']([^"']*)["']\s*/?>`)
	matches := re.FindSubmatch(html)
	if len(matches) > 1 {
		return strings.TrimSpace(string(matches[1]))
	}
	return ""
}

func main() {
	// Simple route setup
	// In a real application, you might use a router like fasthttprouting
	// but for this specific task, we map the handler directly.

	// Handle requests to /preview
	// fasthttp.HandleFunc is not available in the library, use a request handler manually.

	// Handle root
	addr := ":8080"
	log.Printf("Starting server on %s", addr)

	if err := fasthttp.ListenAndServe(addr, func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		case "/":
			ctx.WriteString("URL Preview Service. POST to /preview with JSON body {\"url\": \"...\"}")
		default:
			ctx.Error("Not Found", fasthttp.StatusNotFound)
		}
	}); err != nil {
		log.Fatalf("Error in ListenAndServe: %v", err)
	}
}

