	// 1. Parse JSON body
	var reqBody struct {
		URL string `json:"url"`
	}

	if err := json.Unmarshal(ctx.PostBody(), &reqBody); err != nil {
		ctx.Error("Invalid JSON body", fasthttp.StatusBadRequest)
		return
	}

	if reqBody.URL == "" {
