	}

	// 2. Configure the FastHTTP Client
	// Requirement: MUST set fasthttp.Client.Dial to fasthttp.DialDualStack
	client := &fasthttp.Client{
		Dial: fasthttp.DialDualStack,
		// Requirement: timeout MUST be 3 seconds
		ReadTimeout:  3 * time.Second,
		WriteTimeout: 3 * time.Second,
		MaxConnDuration: 3 * time.Second,
	}

	// 3. Fetch the content
	// Requirement: MUST use fasthttp.Client.DoRedirects method
	req := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(req)

	req.SetRequestURI(reqBody.URL)
	req.Header.SetMethod("GET")

	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)

	if err := client.DoRedirects(req, resp, 10); err != nil {
		log.Printf("Error fetching URL %s: %v", reqBody.URL, err)
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := resp.Body()

	// 4. Parse HTML to extract Title and Meta Description
	// Using regex for simplicity as per standard "preview" logic without external heavy parsers
	// Note: In production, a proper parser like goquery or stdlib html/template is recommended.

	// Extract Title
	title := ""
	titleRegex := regexp.MustCompile(`(?i)<title>(.*?)</title>`)
	titleMatches := titleRegex.FindSubmatch(bodyBytes)
	if len(titleMatches) > 1 {
		title = string(titleMatches[1])
	}

	// Extract Meta Description
	description := ""
	descRegex := regexp.MustCompile(`(?i)<meta\s+name="description"\s+content="(.*?)"`)
	descMatches := descRegex.FindSubmatch(bodyBytes)
	if len(descMatches) > 1 {
		description = string(descMatches[1])
	}

	// Fallback for property="og:description"
	if description == "" {
		ogDescRegex := regexp.MustCompile(`(?i)<meta\s+property="og:description"\s+content="(.*?)"`)
		ogDescMatches := ogDescRegex.FindSubmatch(bodyBytes)
		if len(ogDescMatches) > 1 {
			description = string(ogDescMatches[1])
		}
	}

	// 5. Return JSON response
	result := map[string]string{
		"title":       title,
		"description": description,
	}

	ctx.SetContentType("application/json")

	body, err := json.Marshal(result)
	if err != nil {
		log.Printf("Error marshaling JSON response: %v", err)
		ctx.Error("Internal Server Error", fasthttp.StatusInternalServerError)
		return
	}

	if _, err := ctx.Write(body); err != nil {
		log.Printf("Error writing JSON response: %v", err)
	}
}

func main() {
	// Setup router
	router := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.Error("Not Found", fasthttp.StatusNotFound)
		}
	}

	// Start server
	if err := fasthttp.ListenAndServe(":8080", router); err != nil {
		log.Fatalf("Error in server: %v", err)
	}
}

