// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", fmt.Errorf("failed to parse HTML: %w", err)
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract Title
			if n.Data == "title" && n.FirstChild != nil {
				title = strings.TrimSpace(n.FirstChild.Data)
			}
			// Extract Description
			if n.Data == "meta" {
				attr := getMetaAttr(n, "name")
				if attr == "description" {
					description = getMetaAttr(n, "content")
				} else {
					// Sometimes description is in property="og:description"
					prop := getMetaAttr(n, "property")
					if prop == "og:description" {
						description = getMetaAttr(n, "content")
					}
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return title, description, nil
}

func getMetaAttr(n *html.Node, name string) string {
	for _, attr := range n.Attr {
		if attr.Key == name {
			return attr.Val
		}
	}
	return ""
}

// isLocalAddress checks if the host is a local address (e.g., 127.0.0.1, localhost, 0.0.0.0).
func isLocalAddress(host string) bool {
	lowerHost := strings.ToLower(host)

	// Check for explicit localhost or empty host
	if lowerHost == "localhost" || host == "" {
		return true
	}

	// Check for IPv4 loopback (127.x.x.x)
	ip := net.ParseIP(host)
	if ip != nil {
		if ip.IsLoopback() {
			return true
		}
		// Check for IPv4 unspecified (0.0.0.0)
		if ip.To4() != nil && ip.To4()[0] == 0 {
			return true
		}
	}

	// Check for IPv6 loopback (::1)
	if lowerHost == "::1" {
		return true
	}

	return false
}

