func extractTitle(html string) string {
	// Simple string parsing for <title>
	lowerHTML := strings.ToLower(html)
	titleStart := strings.Index(lowerHTML, "<title")
	if titleStart == -1 {
		return ""
	}

	// Find the closing '>'
	titleStart = strings.Index(lowerHTML[titleStart:], ">")
	if titleStart == -1 {
		return ""
	}
	titleStart += strings.Index(lowerHTML, "<title") + 1

	titleEnd := strings.Index(lowerHTML[titleStart:], "</title>")
	if titleEnd == -1 {
		return ""
	}

	// Extract from original HTML to preserve case
	// We need to map the indices back to the original case-sensitive string
	// However, since we searched in lowerHTML, the indices are valid for the length.
	// We just slice the original html string.

	// Recalculate start based on original HTML
	// Note: The index in lowerHTML corresponds to the index in html because ToLower doesn't change length.
	realStart := titleStart
	realEnd := titleStart + titleEnd

	if realEnd > len(html) {
		return ""
	}

	return strings.TrimSpace(html[realStart:realEnd])
}

