func extractMetaDescription(html string) string {
	lowerHTML := strings.ToLower(html)

	// Look for <meta name="description"
	searchStr := `<meta name="description"`
	idx := strings.Index(lowerHTML, searchStr)
	if idx == -1 {
		// Try single quotes
		searchStr = `<meta name='description'`
		idx = strings.Index(lowerHTML, searchStr)
		if idx == -1 {
			return ""
		}
	}

	// Find content="..." or content='...'
	contentStart := strings.Index(lowerHTML[idx:], `content="`)
	if contentStart == -1 {
		contentStart = strings.Index(lowerHTML[idx:], `content='`)
		if contentStart == -1 {
			return ""
		}
		// Handle single quotes
		startIdx := idx + contentStart + len(`content='`)
		endIdx := strings.Index(lowerHTML[startIdx:], `'`)
		if endIdx == -1 {
			return ""
		}
		return strings.TrimSpace(html[startIdx : startIdx+endIdx])
	}

	// Handle double quotes
	startIdx := idx + contentStart + len(`content="`)
	endIdx := strings.Index(lowerHTML[startIdx:], `"`)
	if endIdx == -1 {
		return ""
	}

	return strings.TrimSpace(html[startIdx : startIdx+endIdx])
}

