	req.Header.SetUserAgent("Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)

	// DoRedirects follows redirects automatically
	err := client.DoRedirects(req, resp, 10) // Max 10 redirects
	if err != nil {
