// RequestPayload defines the JSON request structure
type RequestPayload struct {
	URL string `json:"url"`
}

// ResponsePayload defines the JSON response structure
type ResponsePayload struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

// FastHTTP client configuration with timeouts
var client = &fasthttp.Client{
	ReadTimeout:  5 * time.Second,
	WriteTimeout: 5 * time.Second,
	MaxConnDuration: 10 * time.Second,
	Dial: func(addr string) (net.Conn, error) {
		return fasthttp.DialTimeout(addr, 5*time.Second)
	},
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	var payload RequestPayload

	// Parse JSON body
	if err := json.Unmarshal(ctx.PostBody(), &payload); err != nil {
		ctx.Error("Invalid JSON body", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL
	if payload.URL == "" {
		ctx.Error("URL field is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL format
	parsedURL, err := url.ParseRequestURI(payload.URL)
	if err != nil {
		resp := ResponsePayload{Error: "Invalid URL format"}
		respJSON, _ := json.Marshal(resp)
		ctx.SetContentType("application/json")
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.Write(respJSON)
		return
	}

	// Security: Ensure scheme is http or https
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		resp := ResponsePayload{Error: "Invalid URL scheme"}
		respJSON, _ := json.Marshal(resp)
		ctx.SetContentType("application/json")
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.Write(respJSON)
		return
	}

	// Security: Resolve Host to IP to prevent SSRF via private/local ranges
	host := parsedURL.Host
	if strings.Contains(host, ":") {
		host, _, _ = net.SplitHostPort(host)
	}

	ips, err := net.LookupIP(host)
	if err != nil {
		resp := ResponsePayload{Error: "Failed to resolve host"}
		respJSON, _ := json.Marshal(resp)
		ctx.SetContentType("application/json")
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		ctx.Write(respJSON)
		return
	}

	// Check if any resolved IP is private or loopback
	for _, ip := range ips {
		if ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() {
			resp := ResponsePayload{Error: "Access to private addresses is forbidden"}
			respJSON, _ := json.Marshal(resp)
			ctx.SetContentType("application/json")
			ctx.SetStatusCode(fasthttp.StatusForbidden)
			ctx.Write(respJSON)
			return
		}
	}

	// Prepare request
	req := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(req)
	req.SetRequestURI(payload.URL)
	req.Header.SetMethod("GET")
	req.Header.Set("User-Agent", "URLPreviewBot/1.0")

	// Prepare response
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)

	// Fetch URL using DoRedirects
	err = client.DoRedirects(req, resp, 5) // Max 5 redirects
	if err != nil {
		respPayload := ResponsePayload{Error: fmt.Sprintf("Failed to fetch URL: %v", err)}
		respJSON, _ := json.Marshal(respPayload)
		ctx.SetContentType("application/json")
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		ctx.Write(respJSON)
		return
	}

	// Check content type
	contentType := string(resp.Header.ContentType())
	if !strings.Contains(contentType, "text/html") {
		respPayload := ResponsePayload{Error: "URL did not return HTML content"}
		respJSON, _ := json.Marshal(respPayload)
		ctx.SetContentType("application/json")
		ctx.SetStatusCode(fasthttp.StatusUnsupportedMediaType)
		ctx.Write(respJSON)
		return
	}

	bodyBytes := resp.Body()

	// Limit body size to prevent processing huge files
	if len(bodyBytes) > 1024*1024 { // 1MB limit
		respPayload := ResponsePayload{Error: "Response body too large"}
		respJSON, _ := json.Marshal(respPayload)
		ctx.SetContentType("application/json")
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		ctx.Write(respJSON)
		return
	}

	// Extract Title
	title := extractTitle(bodyBytes)

	// Extract Description
	description := extractMetaDescription(bodyBytes)

	// Send JSON response
	result := ResponsePayload{
		Title:       title,
		Description: description,
	}

	respJSON, err := json.Marshal(result)
	if err != nil {
		ctx.Error("Failed to marshal response", fasthttp.StatusInternalServerError)
		return
	}

	ctx.SetContentType("application/json")
	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.Write(respJSON)
}

// extractTitle parses the HTML body to find the content of the <title> tag
func extractTitle(body []byte) string {
	// Regex to find <title>...</title>
	re := regexp.MustCompile(`(?i)<title[^>]*>(.*?)</title>`)
	matches := re.FindSubmatch(body)
	if len(matches) > 1 {
		return strings.TrimSpace(string(matches[1]))
	}
	return ""
}

// extractMetaDescription parses the HTML body to find the content of the meta description tag
func extractMetaDescription(body []byte) string {
	// Regex to find <meta name="description" content="...">
	re := regexp.MustCompile(`(?i)<meta\s+name=["']description["']\s+content=["']([^"']*)["']`)
	matches := re.FindSubmatch(body)
	if len(matches) > 1 {
		return strings.TrimSpace(string(matches[1]))
	}
	return ""
}

func main() {
	// Simple route setup
	// Note: In a real application, you might use a router like fasthttprouting
	handler := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.Error("Not Found", fasthttp.StatusNotFound)
		}
	}

	fmt.Println("Server starting on :8080...")
	if err := fasthttp.ListenAndServe(":8080", handler); err != nil {
		panic(err)
	}
}

