// extractTitle extracts the content of the <title> tag
func extractTitle(html []byte) string {
	// Simple regex to extract title content.
	// Matches <title>...</title> case-insensitively.
	re := regexp.MustCompile(`(?i)<title>(.*?)</title>`)
	matches := re.FindSubmatch(html)
	if len(matches) > 1 {
		return string(bytes.TrimSpace(matches[1]))
	}
	return ""
}

// extractDescription extracts the content of the <meta name="description" ...> tag
func extractDescription(html []byte) string {
	// Regex to find meta description.
