	"time"

	"github.com/valyala/fasthttp"
)

// RequestPayload represents the incoming JSON request
type RequestPayload struct {
	URL string `json:"url"`
}

// ResponsePayload represents the JSON response
type ResponsePayload struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

// fasthttpClient is the shared client used for fetching URLs
var fasthttpClient = &fasthttp.Client{
	Dial: fasthttp.DialDualStack,
	MaxConnDuration: 10 * time.Second,
	ReadTimeout:     5 * time.Second,
	WriteTimeout:    5 * time.Second,
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	var payload RequestPayload

	// Decode JSON body
	if err := json.Unmarshal(ctx.PostBody(), &payload); err != nil {
		ctx.Error("Invalid JSON body", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL
	if payload.URL == "" {
		ctx.Error("URL field is required", fasthttp.StatusBadRequest)
		return
	}

	// Parse URL to ensure it is valid
	parsedURL, err := url.Parse(payload.URL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}
	if parsedURL.Scheme == "" {
		parsedURL.Scheme = "http"
	}

	// Security: Validate Host to prevent SSRF
	host := parsedURL.Hostname()
	if host == "" {
		ctx.Error("Invalid URL host", fasthttp.StatusBadRequest)
		return
	}

	// Prevent access to localhost or private IPs
	if isPrivateIP(host) {
		ctx.Error("Access to private IPs is not allowed", fasthttp.StatusBadRequest)
		return
	}

	// Prepare the request
	req := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(req)

	req.SetRequestURI(parsedURL.String())
	req.Header.SetMethod("GET")
	req.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Prepare the response
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)

	// Fetch the URL using Do (DoRedirects can be dangerous with SSRF)
	if err := fasthttpClient.Do(req, resp); err != nil {
		log.Printf("Error fetching URL: %s", err)
		response := ResponsePayload{
			Error: fmt.Sprintf("Failed to fetch URL: %v", err),
		}
		writeJSONResponse(ctx, fasthttp.StatusBadGateway, response)
		return
	}

	// Check status code
	if statusCode := resp.StatusCode(); statusCode != fasthttp.StatusOK {
		log.Printf("Unexpected status code: %d", statusCode)
		response := ResponsePayload{
			Error: fmt.Sprintf("Unexpected status code: %d", statusCode),
		}
		writeJSONResponse(ctx, fasthttp.StatusBadGateway, response)
		return
	}

	// Get content type
	contentType := bytes.ToLower(resp.Header.ContentType())
	if !bytes.Contains(contentType, []byte("text/html")) {
		response := ResponsePayload{
			Error: "URL does not return HTML content",
		}
		writeJSONResponse(ctx, fasthttp.StatusOK, response)
		return
	}

	// Parse HTML to extract Title and Description
	body := resp.Body()
	title := extractTitle(string(body))
	description := extractDescription(string(body))

	response := ResponsePayload{
		Title:       title,
		Description: description,
	}

	writeJSONResponse(ctx, fasthttp.StatusOK, response)
}

// writeJSONResponse is a helper to write JSON output
func writeJSONResponse(ctx *fasthttp.RequestCtx, statusCode int, payload interface{}) {
	ctx.SetStatusCode(statusCode)
	ctx.SetContentType("application/json")

	body, err := json.Marshal(payload)
	if err != nil {
		log.Printf("Failed to marshal JSON: %s", err)
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.WriteString(`{"error":"Internal server error"}`)
		return
	}

	ctx.SetBody(body)
}

// extractTitle parses the HTML body and returns the content of the <title> tag
func extractTitle(html string) string {
	// Regex to find <title>...</title>
	re := regexp.MustCompile(`(?i)<title>(.*?)</title>`)
	matches := re.FindStringSubmatch(html)
	if len(matches) > 1 {
		return strings.TrimSpace(matches[1])
	}
	return ""
}

// extractDescription parses the HTML body and returns the content of the meta description tag
func extractDescription(html string) string {
	// Regex to find <meta name="description" content="...">
	re := regexp.MustCompile(`(?i)<meta\s+name=["']description["']\s+content=["'](.*?)["']`)
	matches := re.FindStringSubmatch(html)
	if len(matches) > 1 {
		return strings.TrimSpace(matches[1])
	}

	// Sometimes content comes before name, try alternative pattern
	reAlt := regexp.MustCompile(`(?i)<meta\s+content=["'](.*?)["']\s+name=["']description["']`)
	matchesAlt := reAlt.FindStringSubmatch(html)
	if len(matchesAlt) > 1 {
		return strings.TrimSpace(matchesAlt[1])
	}

	return ""
}

// isPrivateIP checks if the host is a private IP address or localhost
func isPrivateIP(host string) bool {
	lowerHost := strings.ToLower(host)

	// Check for localhost
	if lowerHost == "localhost" {
		return true
	}

	// Check if host is an IP address
	ip := net.ParseIP(host)
	if ip == nil {
		return false
	}

	// Check for private IP ranges
	privateIPBlocks := []string{
		"127.0.0.0/8",    // Loopback
		"10.0.0.0/8",     // RFC1918
		"172.16.0.0/12",  // RFC1918
		"192.168.0.0/16", // RFC1918
		"::1/128",        // Loopback
		"fc00::/7",       // Unique Local Address
		"fe80::/10",      // Link Local
	}

	for _, block := range privateIPBlocks {
		_, cidr, _ := net.ParseCIDR(block)
		if cidr.Contains(ip) {
			return true
		}
	}

	return false
}

func main() {
	// Example usage setup
	// In a real scenario, you would mount this handler to a server
	// e.g. fasthttp.ListenAndServe(":8080", requestHandler)

	// For demonstration purposes, we create a simple request handler wrapper
	// that handles the specific path or acts as a catch-all
	requestHandler := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.Error("Not Found", fasthttp.StatusNotFound)
		}
	}

	if err := fasthttp.ListenAndServe(":8080", requestHandler); err != nil {
		log.Fatalf("Error in server: %s", err)
	}
}

