	WriteTimeout:    5 * time.Second,
}

// FetchURLPreview handles POST requests, fetches the URL content, and extracts metadata.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// 1. Decode JSON Body
	var payload RequestPayload
	decoder := json.NewDecoder(bytes.NewReader(ctx.PostBody()))
	if err := decoder.Decode(&payload); err != nil {
		ctx.Error("Invalid JSON body", fasthttp.StatusBadRequest)
		return
	}

	// 2. Validate URL
	targetURL := strings.TrimSpace(payload.URL)
	if targetURL == "" {
		ctx.Error("URL field is required", fasthttp.StatusBadRequest)
		return
	}

	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

