	// We use a temporary request and response object for the client call.
	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	req.SetRequestURI(targetURL)
	req.Header.SetMethod("GET")
	// Set a User-Agent to avoid being blocked by some servers
	req.Header.SetUserAgent("Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// DoRedirects handles the HTTP redirects automatically
	err = fasthttpClient.DoRedirects(req, resp, 5) // Max 5 redirects
	if err != nil {
		log.Printf("Error fetching URL %s: %v", targetURL, err)
		response := ResponsePayload{Error: fmt.Sprintf("Failed to fetch URL: %v", err)}
		ctx.SetContentType("application/json")
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		json.NewEncoder(ctx).Encode(response)
		return
	}

