// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", fmt.Errorf("failed to parse HTML: %w", err)
	}

	var parseNode func(*html.Node)
	parseNode = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract Title
			if n.Data == "title" && n.FirstChild != nil {
				title = strings.TrimSpace(n.FirstChild.Data)
			}
			// Extract Meta Description
			if n.Data == "meta" {
				attr := getMetaAttr(n, "name")
				if attr == "description" {
					description = getMetaAttr(n, "content")
				}
			}
		}
		// Iterate through children
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			parseNode(c)
		}
	}

	parseNode(doc)
	return title, description, nil
}

// getMetaAttr retrieves a specific attribute value from a meta node.
func getMetaAttr(n *html.Node, name string) string {
	for _, attr := range n.Attr {
		if attr.Key == name {
			return attr.Val
		}
	}
	return ""
}

// isPrivateIP checks if the given host is a private IP address or localhost.
// This is a simplified check for demonstration; in production, use a robust IP parsing library.
func isPrivateIP(host string) bool {
	// Remove port if present
	if strings.Contains(host, ":") {
		host = strings.Split(host, ":")[0]
	}

	// Check for localhost
	if host == "localhost" || host == "127.0.0.1" || host == "::1" {
		return true
	}

	// Check for private IP ranges (IPv4)
	// 10.0.0.0/8
	if strings.HasPrefix(host, "10.") {
		return true
	}
	// 172.16.0.0/12
	if strings.HasPrefix(host, "172.") {
		parts := strings.Split(host, ".")
		if len(parts) == 4 {
			secondOctet, err := parseInt(parts[1])
			if err == nil && secondOctet >= 16 && secondOctet <= 31 {
				return true
			}
		}
	}
	// 192.168.0.0/16
	if strings.HasPrefix(host, "192.168.") {
		return true
	}
	// 169.254.0.0/16 (Link-local)
	if strings.HasPrefix(host, "169.254.") {
		return true
	}

	// Check for private IP ranges (IPv6)
	// fc00::/7 (Unique local)
	if strings.HasPrefix(host, "fc") || strings.HasPrefix(host, "fd") {
		return true
	}
	// fe80::/10 (Link-local)
	if strings.HasPrefix(host, "fe8") || strings.HasPrefix(host, "fe9") || 
	   strings.HasPrefix(host, "fea") || strings.HasPrefix(host, "feb") {
		return true
	}

	return false
}

// parseInt is a helper to parse string to int.
func parseInt(s string) (int, error) {
	return strconv.Atoi(s)
}

